#include <cstdio>
#include <cstdlib>
#include <omp.h>

#define N 1024
#define T 100

void stencil_1d(float *in, float *out, int n) {
    #pragma omp parallel for
    for (int i = 1; i < n - 1; i++) {
        out[i] = 0.25f * in[i - 1] + 0.5f * in[i] + 0.25f * in[i + 1];
    }
}

int main() {
    float *in = (float*)malloc(N * sizeof(float));
    float *out = (float*)malloc(N * sizeof(float));

    for (int i = 0; i < N; i++) {
        in[i] = static_cast<float>(i);
    }

    for (int t = 0; t < T; t++) {
        stencil_1d(in, out, N);
        float *temp = in;
        in = out;
        out = temp;
    }

    for (int i = 0; i < N; i++) {
        printf("%f\n", in[i]);
    }

    free(in);
    free(out);

    return 0;
}
